import React, { useState, useEffect } from "react";
import { makeStyles } from "@material-ui/core/styles";
import MaterialTable from "material-table";
import clsx from "clsx";
import { useNavigate } from "react-router-dom";
import {
  Button,
  Paper,
  Grid,
  Icon,
  Divider,
  TextField,
} from "@material-ui/core";
import {
  Box,
  Modal,
  ModalOverlay,
  ModalContent,
  ModalHeader,
  ModalFooter,
  ModalBody,
  ModalCloseButton,
  //Select,
  useDisclosure,
} from "@chakra-ui/react";
// import {
//   Input,
//   InputGroup,
//   InputLeftAddon,
//   NumberInput,
//   NumberInputField,
//   NumberInputStepper,
//   NumberIncrementStepper,
//   NumberDecrementStepper,
//   Stack,
//} from "@chakra-ui/react";
import { useRecoilState } from "recoil";
import { useEmployeesContext } from "../context/employees_context";
import { usePayslipsContext } from "../context/payslips_context";
import { useExpensesContext } from "../context/expenses_context";
import { useDailyAllowancesContext } from "../context/dailyallowances_context";
import { payrunState, payrunIdState } from "./data/atomdata";
//import { usePayrun } from "./payrun/usePayrun";
import { useCurrency } from "./currency/useCurrency";
//import { useExpenses } from "./expenses/useExpenses";
import UpdateCurrency from "./CurrencyTable";
//import { usePayslipsBatch } from "./payslips/usePayslipsBatch";

//const drawerWidth = 240;

const columns = [
  {
    title: "NAME",
    field: "name",
    editable: "never",
    cellStyle: {
      width: 280,
      maxWidth: 280,
    },
  },
];

// const selectmonths = [
//   { mth: "January" },
//   { mth: "February" },
//   { mth: "March" },
//   { mth: "April" },
//   { mth: "May" },
//   { mth: "June" },
//   { mth: "July" },
//   { mth: "August" },
//   { mth: "September" },
//   { mth: "October" },
//   { mth: "November" },
//   { mth: "December" },
// ];

const Payrun = () => {
  let navigate = useNavigate();
  //let date = new Date();
  //let longMonth = date.toLocaleString("en-us", { month: "long" });

  const classes = useStyles();
  const fixedHeightPaper = clsx(classes.paper, classes.fixedHeight);
  //const { payrun } = usePayrun();
  //const { payslipsbatch, psbpayrunId, setPSBPayrunId } = usePayslipsBatch();
  const { currency } = useCurrency();
  //const { expenses, setPayrunId } = useExpensesPayrun();
  const { isOpen, onOpen, onClose } = useDisclosure();
  const [loadPaybatch, setLoadPaybatch] = useState(false);
  const { loadEmployees, employees } = useEmployeesContext();
  const { loadUnpaidExpenses,  unpaidexpenses, updateExpense } =
    useExpensesContext();
  const { unpaiddailyallows, loadUnpaidDailyAllows, updateDailyAllowance } =
    useDailyAllowancesContext();
  const {
    addPayrun,
    getPayrun,
    payrun,
    payrun_loading,
    addPayslip,
    resetPayslipsData,
    singlebatch_payslip_loading,
    setPayslipPeriod,
  } = usePayslipsContext();
  const [input, setInput] = useRecoilState(payrunState);
  const [payrunid, setPayrunId] = useRecoilState(payrunIdState);
  const [alert, setAlert] = useState(false);
  const [error] = useState(false);
  const [errornoselect, setErrornoselect] = useState(false);
  const [isPayrunExist, setIsPayrunExist] = useState(false);
  const [isSubmit, setIsSubmit] = useState(false);

  //filter regisned employees
  const allemployees = employees.filter((r) => !r.hasresigned && !r.nonpayroll)

  useEffect(() => {
    if (!payrun_loading) {
      setLoadPaybatch(false);
    }
  }, [loadPaybatch]);

  function formatDate(string) {
    var options = { year: "numeric", month: "long", day: "numeric" };
    return new Date(string).toLocaleDateString("en-GB", options);
  }

  function formatPayrun() {
    // const yy =
    //   input.fromdate.substring(0, 4) + "-" + input.fromdate.substring(5, 7);
    // const mm = input.fromdate.substring(5, 7);
    // const d = input.fromdate;
  }

  const payrunExists = (data) => {
    return payrun.some(function (el) {
      return el.payrun === data;
    });
  };
  const handleChange = (e) => {
    setInput({ ...input, [e.target.name]: e.target.value });
  };

  const handlePayrunSubmit = (e) => {
    e.preventDefault();
    setPayrunId("");
    var count = allemployees.reduce((acc, r) => {
      if (r.tableData.checked) {
        return acc + 1;
      } else {
        return acc;
      }
    }, 0);
    //console.log("count", count);
    if (count === 0) {
      setErrornoselect(true);
      setTimeout(() => {
        setErrornoselect(false);
      }, 3000);
      return null;
    }

    const period =
      formatDate(input.fromdate) + " - " + formatDate(input.todate);
    const payrundata =
      input.fromdate.substring(0, 4) + "-" + input.fromdate.substring(5, 7);
    setInput({
      ...input,
      period: period,
      payrun: payrundata,
      status: "New",
    });
    formatPayrun();
    setPayslipPeriod(payrundata);
    const isExist = payrunExists(payrundata);

    if (isExist) {
      //console.log("exist");
      setIsPayrunExist(true);
      setIsSubmit(false);
      setAlert(true);
    } else {
      //console.log("add");
      checkSelectedEmployees(period, payrundata);
      add_Payrun(period, payrundata);
      setIsPayrunExist(false);
      setAlert(true);
      setIsSubmit(true);
      setLoadPaybatch(true);
    }
  };

  const checkSelectedEmployees = (period, payrun) => {
    //console.log("payrun", payrun, period);
    var exp = 0,
      allows = 0,
      tmpbasicsalary = 0,
      tmptotalallows = 0,
      tmptotalTAP = 0,
      tmptotalSCP = 0,
      //tmpsiteallows = 0,
      //tmpexpsclaims = 0,
      tmpnettpay = 0,
      tmpcurrrate = 0,
      tmpbasicsalarybnd = 0,
      tmptotalallowsbnd = 0,
      tmptotalTAPbnd = 0,
      tmptotalSCPbnd = 0,
      tmpsiteallowsbnd = 0,
      tmpexpsclaimsbnd = 0,
      tmpnettpaybnd = 0;

    resetPayslipsData();
    allemployees &&
      allemployees.forEach((emp, index) => {
        exp = 0;
        allows = 0;
        tmpbasicsalary = 0;
        tmptotalallows = 0;
        tmptotalTAP = 0;
        tmptotalSCP = 0;
        tmpnettpay = 0;
        tmpcurrrate = 0;
        tmpbasicsalarybnd = 0;
        tmptotalallowsbnd = 0;
        tmptotalTAPbnd = 0;
        tmpsiteallowsbnd = 0;
        tmpexpsclaimsbnd = 0;
        tmptotalSCPbnd = 0;
        tmpnettpaybnd = 0;

        if (emp.tableData.checked) {
          exp = 0;
          if (unpaidexpenses) {
            unpaidexpenses
              .filter((r) => r.empid === emp.id)
              .map((i) => {
                updateExpense({ id: i.id, payrun: payrun });
                return (exp = exp + i.amount);
              });
          }
          allows = 0;
          if (unpaiddailyallows) {
            unpaiddailyallows
              .filter((r) => r.empid === emp.id)
              .map((i) => {
                updateDailyAllowance({ id: i.id, payrun: payrun });
                return (allows = allows + i.amount);
              });
          }

          const {
            id,
            name,
            bank_name,
            bank_acno,
            basic_salary,
            salary_currency,
            tap_acno,
            scp_acno,
            tap_checkbox,
          } = emp;

          tmpbasicsalary = basic_salary;

          if (salary_currency && salary_currency !== "BND") {
            const table = currency
              .filter((r) => r.currency === salary_currency)
              .map((rec) => {
                return { ...rec };
              });
            tmpcurrrate = table[0].rate;
          } else {
            tmpcurrrate = 1;
          }

          //console.log("USD", table, basic_salary, tmpbasicsalary);
          //tmptotalallows = allows + exp;
          tmptotalTAP = tap_checkbox ? Math.ceil(tmpbasicsalary * 0.05) : 0;
          tmptotalSCP = tap_checkbox
            ? Math.round((tmpbasicsalary + Number.EPSILON) * 0.035 * 100) / 100
            : 0;
          if (tmptotalSCP > 98) {
            tmptotalSCP = 98;
          }
          tmpnettpay =
            tmpbasicsalary +
            allows +
            exp +
            tmptotalallows -
            tmptotalTAP -
            tmptotalSCP;

          tmpbasicsalarybnd =
            Math.round((basic_salary + Number.EPSILON) * tmpcurrrate * 100) /
            100;

          tmptotalTAPbnd =
            Math.round((tmptotalTAP + Number.EPSILON) * tmpcurrrate * 100) /
            100;
          tmptotalSCPbnd =
            Math.round((tmptotalSCP + Number.EPSILON) * tmpcurrrate * 100) /
            100;
          tmpnettpaybnd =
            Math.round((tmpnettpay + Number.EPSILON) * tmpcurrrate * 100) / 100;
          tmpsiteallowsbnd =
            Math.round((allows + Number.EPSILON) * tmpcurrrate * 100) / 100;
          tmpexpsclaimsbnd =
            Math.round((exp + Number.EPSILON) * tmpcurrrate * 100) / 100;

          tmpnettpaybnd =
            tmpbasicsalarybnd +
            tmpsiteallowsbnd +
            tmpexpsclaimsbnd -
            tmptotalTAPbnd -
            tmptotalSCPbnd;

          const data = {
            name: name,
            period: period,
            pay_date: input.pay_date,
            payrun: payrun,
            bank_name: bank_name,
            bank_acno: bank_acno,
            salary_currency: salary_currency ? salary_currency : "BND",
            currency_rate: tmpcurrrate,
            tap_acno: tap_acno,
            scp_acno: scp_acno,
            tap_checkbox: tap_checkbox,
            empid: id,
            status: "Pending",
            allows_type1: "Site Allowances",
            allows_type1amt: allows,
            allows_type2: "Expenses Claims",
            allows_type2amt: exp,
            allows_type3: " ",
            allows_type3amt: 0,
            allows_type4: " ",
            allows_type4amt: 0,
            allows_type5: " ",
            allows_type5amt: 0,
            allows_type6: " ",
            allows_type6amt: 0,
            allows_type7: " ",
            allows_type7amt: 0,
            allows_type8: " ",
            allows_type8amt: 0,
            deducts_type1: " ",
            deducts_type1amt: 0,
            deducts_type2: " ",
            deducts_type2amt: 0,
            deducts_type3: " ",
            deducts_type3amt: 0,
            deducts_type4: " ",
            deducts_type4amt: 0,
            deducts_type5: " ",
            deducts_type5amt: 0,
            deducts_type6: " ",
            deducts_type6amt: 0,
            deducts_type7: " ",
            deducts_type7amt: 0,
            deducts_type8: " ",
            deducts_type8amt: 0,

            wages: tmpbasicsalary,
            tap_amount: tmptotalTAP,
            scp_amount: tmptotalSCP,
            total_allowances: tmptotalallows,
            total_deductions: 0,
            site_allows: allows,
            expenses_claims: exp,
            nett_pay: tmpnettpay,

            wages_bnd: tmpbasicsalarybnd,
            site_allows_bnd: tmpsiteallowsbnd,
            expenses_claims_bnd: tmpexpsclaimsbnd,
            total_allowances_bnd: tmptotalallowsbnd,
            total_deductions_bnd: 0,
            tap_amount_bnd: tmptotalTAPbnd,
            scp_amount_bnd: tmptotalSCPbnd,
            nett_pay_bnd: tmpnettpaybnd,
          };
          addPayslip({ ...data });
        }
      });
  };

  const handleNext = () => {
    navigate("/payrunbatch");
  };

  const add_Payrun = (period, payrun) => {
    //update payrun
    addPayrun({
      pay_freq: input.payfreq,
      from_date: input.fromdate,
      to_date: input.todate,
      pay_date: input.paydate,
      period: period,
      payrun: payrun,
      status: "Pending",
    });
    getPayrun();
  };

  useEffect(() => {
    loadEmployees();
    loadUnpaidExpenses();
    loadUnpaidDailyAllows();
    getPayrun();
  }, []);

  // useEffect(() => {
  //   loadUnpaidDailyAllows();
  // }, []);

  // useEffect(() => {
  //   console.log("useEffect here", input.payrun);

  //   // getSingleBatchPayslip(input.payrun);
  //   if (singlebatchpayslip) {
  //     checkSelectedEmployees(input.period, input.payrun);
  //     setLoadPaybatch(false);
  //   }
  // }, [loadPaybatch]);

  //   useEffect(() => {
  //     if (input.period && input.payrun) {
  //       //add_Payrun();

  //       setAlert(true);
  //     }
  //   }, [input]);

  return (
    <Paper className={fixedHeightPaper} style={{ backgroundColor: "659dbd" }}>
      <section className={classes.section}>
        <Grid
          direction="row"
          container
          spacing={1}
          // style={{ border: "1px solid white" }}
        >
          <Grid
            container
            item
            sm={3}
            style={{ border: "1px solid black" }}
            direction="column"
            align="left"
          >
            <article className={classes.jobinfo}>
              <h2>Pay Run</h2>
              <form onSubmit={handlePayrunSubmit}>
                <div>
                  {/* <InputLabel
                    htmlFor="deduct-customized-native-simple"
                    className={classes.formLabel}
                  >
                    Copy From
                  </InputLabel>
                  <NativeSelect
                    name="copyfrom"
                    value={"New"}
                    style={{
                      padding: 4,
                      marginLeft: 5,
                      width: "100%",
                      textAlign: "left",
                    }}
                    onChange={(e) => handleChange(e)}
                  >
                    <option value="">New</option>
                    {payrun.map((row) => {
                      return (
                        <option key={row.id} value={row.payrun}>
                          {row.payrun}
                        </option>
                      );
                    })}
                  </NativeSelect> */}
                </div>
                <div>
                  <TextField
                    label="Pay Frequency"
                    variant="filled"
                    required
                    defaultValue="Monthly"
                    style={{ width: "100%" }}
                    name="payfreq"
                    value={input.payfreq}
                    onChange={(e) => handleChange(e)}
                    select
                  >
                    {/* <MenuItem value="Weekly">Weekly</MenuItem> */}
                    <option value="Monthly">Monthly</option>
                  </TextField>
                </div>
                {/* <div>
                  <InputLabel
                    htmlFor="deduct-customized-native-simple"
                    className={classes.formLabel}
                  >
                    Month
                  </InputLabel>
                  <NativeSelect
                    name="selectmonth"
                    defaultValue={longMonth}
                    // value={input.selectmonth}
                    style={{
                      padding: 4,
                      marginLeft: 5,
                      width: "100%",
                      textAlign: "left",
                    }}
                    onChange={(e) => handleChange(e)}
                  >
                    {selectmonths.map((row, i) => {
                      return (
                        <option key={i} value={row.mth}>
                          {row.mth}
                        </option>
                      );
                    })}
                  </NativeSelect>
                </div> */}
                <div>
                  <TextField
                    label="From Date"
                    variant="filled"
                    name="fromdate"
                    type="date"
                    value={input.fromdate}
                    required
                    style={{ width: "100%" }}
                    onChange={(e) => handleChange(e)}
                    InputLabelProps={{
                      shrink: true,
                    }}
                  />
                </div>
                <div>
                  <TextField
                    label="To Date"
                    variant="filled"
                    type="date"
                    name="todate"
                    value={input.todate}
                    required
                    onChange={(e) => handleChange(e)}
                    style={{ width: "100%" }}
                    InputLabelProps={{
                      shrink: true,
                    }}
                  />
                </div>
                <div>
                  <TextField
                    label="Payment Date"
                    variant="filled"
                    type="date"
                    name="paydate"
                    value={input.paydate}
                    required
                    style={{ width: "100%" }}
                    onChange={(e) => handleChange(e)}
                    InputLabelProps={{
                      shrink: true,
                    }}
                  />
                </div>
                <div>
                  <div>
                    <Button
                      variant="contained"
                      color="primary"
                      className={classes.button}
                      onClick={onOpen}
                      disabled={isSubmit}
                    >
                      Currency Exchange Table
                    </Button>
                  </div>
                  <div>
                    <Button
                      type="submit"
                      variant="contained"
                      color="primary"
                      className={classes.button}
                    >
                      Submit <Icon className={classes.rightIcon}>send</Icon>
                    </Button>

                    {alert && !isPayrunExist && (
                      <Button
                        type="submit"
                        variant="contained"
                        color="primary"
                        className={classes.button}
                        onClick={handleNext}
                      >
                        Next <Icon className={classes.rightIcon}>send</Icon>
                      </Button>
                    )}
                  </div>
                </div>
                <div>
                  {alert && !isPayrunExist && !singlebatch_payslip_loading && (
                    <h3>New Payrun being added!</h3>
                  )}
                  {alert && isPayrunExist && (
                    <h3>This payrun already existed!</h3>
                  )}
                </div>
                <div>
                  {error && <h3>This Payrun period already existed!</h3>}
                  {errornoselect && <h3>You must select employees!</h3>}
                </div>
              </form>
            </article>
          </Grid>
          <Divider
            orientation="vertical"
            flexItem
            style={{ background: "white" }}
          />
          <Grid
            container
            item
            sm={3}
            style={{ border: "1px solid black" }}
            align="right"
          >
            <Box h="500" w="full" overflow="scroll">
              <MaterialTable
                columns={columns}
                //data={employees.filter((r) => !r.hasresigned && !r.nonpayroll)}
                data={allemployees}
                title="Employee Listing"
                options={{
                  filtering: false,
                  search: false,
                  toolbar: true,
                  selection: true,
                  paging: false,
                  pageSize: 10,
                  headerStyle: {
                    backgroundColor: "#90CDF4",
                    color: "primary",
                  },
                  showTitle: true,
                  // selectionProps: rowData => {
                  //   rowData.tableData.checked = true
                  // }
                }}
              />
            </Box>
          </Grid>
        </Grid>
        <Modal isOpen={isOpen} onClose={onClose}>
          <ModalOverlay />
          <ModalContent>
            <ModalHeader>Currency Table</ModalHeader>
            <ModalCloseButton />
            <ModalBody>
              <Box>
                <UpdateCurrency />
                {/* <Stack spacing={4}>
                  <InputGroup>
                    <InputLeftAddon children="USD" />
                    <Input type="text" placeholder="USD Rate" />
                  </InputGroup>
                  <InputGroup>
                    <InputLeftAddon children="MYR" />
                    <Input type="text" placeholder="MYR Rate" />
                  </InputGroup>
                </Stack> */}
              </Box>
            </ModalBody>

            <ModalFooter>
              <Button colorScheme="blue" mr={3} onClick={onClose}>
                Close
              </Button>
            </ModalFooter>
          </ModalContent>
        </Modal>
      </section>
    </Paper>
  );
};

const useStyles = makeStyles((theme) => ({
  root: {
    flexGrow: 1,
  },
  button: {
    margin: theme.spacing(1),
  },
  container: {
    margin: 0,
    padding: 0,
    width: "80vw",
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill,250px)",
    gridAutoRows: "10px",
    position: "absolute",
    left: "50%",
    transform: "translateX(-50%)",
    justifyContent: "center",
    backgroundColor: "primary",
  },
  fixedHeight: {
    height: 800,
  },
  paper: {
    padding: theme.spacing(10),
    // display: "flex",
    display: "flex",
    overflow: "auto",
    flexDirection: "column",
    border: "1px solid",
    width: "100%",
    color: "primary",
    bcakgroundColor: "black",
  },
  card: {
    backgroundColor: "black",
  },
  section: {
    width: "95vw",
    margin: "5rem auto",
    maxWidth: "var(--max-width)",
  },
  underline: {
    width: "5rem",
    height: "0.25rem",
    marginBottom: "1.25rem",
    background: "var(--clr-primary-5)",
    marginLeft: "auto",
    marginRight: "auto",
  },
  title: {
    marginbottom: "4rem",
    textAlign: "center",
  },
  jobscenter: {
    width: "80vw",
    margin: "0 auto",
    maxWidth: "var(--max-width)",
    flexDirection: "row",
  },
  btncontainer: {
    display: "flex",
    flexDirection: "row",
    justifyContent: "center",
    marginBottom: "4rem",
    flexWrap: "wrap",
  },
  jobbtn: {
    background: "transparent",
    borderColor: "transparent",
    textTransform: "capitalize",
    fontSize: "1.25rem",
    letterSpacing: "var(--spacing)",
    margin: "0 0.5rem",
    transition: "var(--transition)",
    cursor: "pointer",
    padding: "0.25rem 0",
    lineHeight: "1",
    outlineColor: "var(--clr-primary-10)",
    "&:hover": {
      color: "var(--clr-primary-5)",
      boxShadow: "0 2px var(--clr-primary-5)",
    },
  },
  activebtn: {
    color: "var(--clr-primary-5)",
    boxShadow: "0 2px var(--clr-primary-5)",
  },
  jobinfo: {
    fontWeight: "400",
  },
  rightIcon: {
    marginLeft: theme.spacing(1),
  },
  formLabel: {
    fontSize: 12,
    textAlign: "left",
    marginLeft: 8,
    marginTop: 5,
  },
}));

export default Payrun;
